            binding.tvQuote.text = when (quoteResource) {
                is Resource.Success -> "\"${quoteResource.data.content}\" — ${quoteResource.data.author}"
                is Resource.Error -> getString(R.string.quote_unavailable)
                Resource.Loading -> getString(R.string.loading_quote)
            }
        }
    }

    private fun checkLocationPermissionAndLoadWeather() {
        val fineGranted = ContextCompat.checkSelfPermission(
            requireContext(), Manifest.permission.ACCESS_FINE_LOCATION
        ) == PackageManager.PERMISSION_GRANTED
        val coarseGranted = ContextCompat.checkSelfPermission(
            requireContext(), Manifest.permission.ACCESS_COARSE_LOCATION
        ) == PackageManager.PERMISSION_GRANTED
        if (fineGranted || coarseGranted) fetchLocationAndLoadWeather()
        else locationPermissionRequest.launch(
            arrayOf(
                Manifest.permission.ACCESS_FINE_LOCATION,
                Manifest.permission.ACCESS_COARSE_LOCATION
            )
        )
    }

    @SuppressLint("MissingPermission")
    private fun fetchLocationAndLoadWeather() {
        fusedLocationClient.lastLocation.addOnSuccessListener { location ->
            if (location != null) viewModel.loadWeather(location.latitude, location.longitude)
            else viewModel.loadWeather(Constants.DEFAULT_LATITUDE, Constants.DEFAULT_LONGITUDE)
        }.addOnFailureListener {
            viewModel.loadWeather(Constants.DEFAULT_LATITUDE, Constants.DEFAULT_LONGITUDE)
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.habitpal.presentation.home

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.habitpal.data.local.UserPreferencesDataSource
import com.example.habitpal.domain.model.Category
import com.example.habitpal.domain.model.Habit
import com.example.habitpal.domain.model.Quote
import com.example.habitpal.domain.model.Weather
import com.example.habitpal.domain.repository.CategoryRepository
import com.example.habitpal.domain.repository.HabitRepository
import com.example.habitpal.domain.usecase.habit.CompleteHabitUseCase
import com.example.habitpal.domain.usecase.habit.GetHabitsUseCase
import com.example.habitpal.domain.usecase.quote.GetQuoteUseCase
import com.example.habitpal.domain.usecase.weather.GetWeatherUseCase
import com.example.habitpal.util.Resource
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch
import javax.inject.Inject

@HiltViewModel
class HomeViewModel @Inject constructor(
    private val getHabitsUseCase: GetHabitsUseCase,
    private val completeHabitUseCase: CompleteHabitUseCase,
    private val getWeatherUseCase: GetWeatherUseCase,
    private val getQuoteUseCase: GetQuoteUseCase,
    private val userPreferences: UserPreferencesDataSource,
    private val habitRepository: HabitRepository,
    private val categoryRepository: CategoryRepository
) : ViewModel() {

    private val _allHabits = MutableStateFlow<List<Habit>>(emptyList())

    private val _weather = MutableStateFlow<Resource<Weather>>(Resource.Loading)
    val weather: StateFlow<Resource<Weather>> = _weather.asStateFlow()

    private val _quote = MutableStateFlow<Resource<Quote>>(Resource.Loading)
    val quote: StateFlow<Resource<Quote>> = _quote.asStateFlow()

    private val _userName = MutableStateFlow("User")
    val userName: StateFlow<String> = _userName.asStateFlow()

    private val _selectedCategory = MutableStateFlow<Category?>(null)
    val selectedCategory: StateFlow<Category?> = _selectedCategory.asStateFlow()

    val categories: StateFlow<List<Category>> = categoryRepository.getAll()
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptyList())

    val habits: StateFlow<List<Habit>> = combine(_allHabits, _selectedCategory) { habits, cat ->
        if (cat == null) habits
        else habits.filter { it.categoryId == cat.id }
    }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptyList())

    init {
        loadHabits()
        loadQuote()
        loadUserName()
    }

    private fun loadUserName() {
        viewModelScope.launch {
            userPreferences.userName.collect { _userName.value = it }
        }
    }

    private fun loadHabits() {
        viewModelScope.launch {
            getHabitsUseCase().collect { _allHabits.value = it }
        }
    }

    fun loadWeather(lat: Double, lon: Double) {
        viewModelScope.launch {
            _weather.value = Resource.Loading
            _weather.value = getWeatherUseCase(lat, lon)
        }
    }

    private fun loadQuote() {
        viewModelScope.launch {
            _quote.value = Resource.Loading
            _quote.value = getQuoteUseCase()
        }
    }

    fun completeHabit(habitId: Int, note: String? = null) {
        viewModelScope.launch {
            completeHabitUseCase(habitId, note)
        }
    }

    fun selectCategory(category: Category?) {
        _selectedCategory.value = if (_selectedCategory.value == category) null else category
    }

    fun reorderHabits(fromPos: Int, toPos: Int) {
        val currentList = _allHabits.value.toMutableList()
        if (fromPos < 0 || toPos < 0 || fromPos >= currentList.size || toPos >= currentList.size) return
        val moved = currentList.removeAt(fromPos)
        currentList.add(toPos, moved)
        _allHabits.value = currentList
        viewModelScope.launch(Dispatchers.IO) {
            val updates = currentList.mapIndexed { index, habit -> Pair(habit.id, index) }
            habitRepository.updateSortOrders(updates)
        }
    }
}

package com.example.habitpal.presentation.home

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.habitpal.data.local.UserPreferencesDataSource
import com.example.habitpal.domain.model.Category
import com.example.habitpal.domain.model.Habit
import com.example.habitpal.domain.model.Quote
import com.example.habitpal.domain.model.Weather
import com.example.habitpal.domain.repository.CategoryRepository
import com.example.habitpal.domain.repository.HabitRepository
import com.example.habitpal.domain.usecase.habit.CompleteHabitUseCase
import com.example.habitpal.domain.usecase.habit.GetHabitsUseCase
import com.example.habitpal.domain.usecase.SeedCategoriesUseCase
import com.example.habitpal.domain.usecase.quote.GetQuoteUseCase
import com.example.habitpal.domain.usecase.weather.GetWeatherUseCase
import com.example.habitpal.util.Resource
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch
import javax.inject.Inject

@HiltViewModel
class HomeViewModel @Inject constructor(
    private val getHabitsUseCase: GetHabitsUseCase,
    private val completeHabitUseCase: CompleteHabitUseCase,
    private val getWeatherUseCase: GetWeatherUseCase,
    private val getQuoteUseCase: GetQuoteUseCase,
    private val userPreferences: UserPreferencesDataSource,
    private val habitRepository: HabitRepository,
    categoryRepository: CategoryRepository,
    private val seedCategoriesUseCase: SeedCategoriesUseCase
) : ViewModel() {

    private val _allHabits = MutableStateFlow<List<Habit>>(emptyList())

    private val _weather = MutableStateFlow<Resource<Weather>>(Resource.Loading)
    val weather: StateFlow<Resource<Weather>> = _weather.asStateFlow()

    private val _quote = MutableStateFlow<Resource<Quote>>(Resource.Loading)
    val quote: StateFlow<Resource<Quote>> = _quote.asStateFlow()

    private val _userName = MutableStateFlow("User")
    val userName: StateFlow<String> = _userName.asStateFlow()

    private val _selectedCategory = MutableStateFlow<Category?>(null)
    val selectedCategory: StateFlow<Category?> = _selectedCategory.asStateFlow()

    val categories: StateFlow<List<Category>> = categoryRepository.getAll()
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptyList())

    val habits: StateFlow<List<Habit>> = combine(_allHabits, _selectedCategory) { habits, cat ->
        if (cat == null) habits
        else habits.filter { it.categoryId == cat.id }
    }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptyList())

    init {
        seedCategories()
        loadHabits()
        loadQuote()
        loadUserName()
    }

    private fun seedCategories() {
        viewModelScope.launch(Dispatchers.IO) {
            seedCategoriesUseCase.seedIfEmpty()
        }
    }

    private fun loadUserName() {
        viewModelScope.launch {
            userPreferences.userName.collect { _userName.value = it }
        }
    }

    private fun loadHabits() {
        viewModelScope.launch {
            getHabitsUseCase().collect { _allHabits.value = it }
        }
    }

    fun loadWeather(lat: Double, lon: Double) {
        viewModelScope.launch {
            _weather.value = Resource.Loading
            _weather.value = getWeatherUseCase(lat, lon)
        }
    }

    private fun loadQuote() {
        viewModelScope.launch {
            _quote.value = Resource.Loading
            _quote.value = getQuoteUseCase()
        }
    }

    fun completeHabit(habitId: Int, note: String? = null) {
        viewModelScope.launch {
            completeHabitUseCase(habitId, note)
        }
    }

    fun selectCategory(category: Category?) {
        _selectedCategory.value = if (_selectedCategory.value == category) null else category
    }

    fun reorderHabits(fromPos: Int, toPos: Int) {
        val currentList = _allHabits.value.toMutableList()
        if (fromPos < 0 || toPos < 0 || fromPos >= currentList.size || toPos >= currentList.size) return
        val moved = currentList.removeAt(fromPos)
        currentList.add(toPos, moved)
        _allHabits.value = currentList
        viewModelScope.launch(Dispatchers.IO) {
            val updates = currentList.mapIndexed { index, habit -> Pair(habit.id, index) }
            habitRepository.updateSortOrders(updates)
        }
    }
}

package com.example.habitpal.presentation.onboarding

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.Fragment
import androidx.fragment.app.viewModels
import androidx.navigation.fragment.findNavController
import androidx.recyclerview.widget.GridLayoutManager
import com.example.habitpal.R
import com.example.habitpal.databinding.FragmentOnboardingBinding
import dagger.hilt.android.AndroidEntryPoint

@AndroidEntryPoint
class OnboardingFragment : Fragment() {

    private var _binding: FragmentOnboardingBinding? = null
    private val binding get() = _binding!!
    private val viewModel: OnboardingViewModel by viewModels()

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        _binding = FragmentOnboardingBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        val adapter = HabitTemplateAdapter { template ->
            viewModel.toggleTemplate(template)
        }
        binding.rvTemplates.layoutManager = GridLayoutManager(requireContext(), 2)
        binding.rvTemplates.adapter = adapter
        adapter.submitList(viewModel.templates)

        binding.btnSkip.setOnClickListener {
            viewModel.skipOnboarding { navigateHome() }
        }

        binding.btnGetStarted.setOnClickListener {
            viewModel.finishOnboarding { navigateHome() }
        }
    }

    private fun navigateHome() {
        findNavController().navigate(R.id.action_onboarding_to_home)
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.habitpal.presentation.onboarding

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.Fragment
import androidx.fragment.app.viewModels
import androidx.navigation.fragment.findNavController
import androidx.recyclerview.widget.GridLayoutManager
import com.example.habitpal.R
import com.example.habitpal.databinding.FragmentOnboardingBinding
import com.example.habitpal.util.collectFlow
import dagger.hilt.android.AndroidEntryPoint

@AndroidEntryPoint
class OnboardingFragment : Fragment() {

    private var _binding: FragmentOnboardingBinding? = null
    private val binding get() = _binding!!
    private val viewModel: OnboardingViewModel by viewModels()

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        _binding = FragmentOnboardingBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        val adapter = HabitTemplateAdapter { template ->
            viewModel.toggleTemplate(template)
        }
        binding.rvTemplates.layoutManager = GridLayoutManager(requireContext(), 2)
        binding.rvTemplates.adapter = adapter
        adapter.submitList(viewModel.templates)

        viewLifecycleOwner.collectFlow(viewModel.userName) { name ->
            val cleanName = name.trim().ifEmpty { getString(R.string.default_user_name) }
            binding.tvOnboardingSubtitle.text =
                getString(R.string.pick_habits_subtitle_personalized, cleanName)
        }

        binding.btnSkip.setOnClickListener {
            viewModel.skipOnboarding { navigateHome() }
        }

        binding.btnGetStarted.setOnClickListener {
            viewModel.finishOnboarding { navigateHome() }
        }
    }

    private fun navigateHome() {
        findNavController().navigate(R.id.action_onboarding_to_home)
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.example.habitpal.presentation.onboarding

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.habitpal.data.local.UserPreferencesDataSource
import com.example.habitpal.domain.model.Habit
import com.example.habitpal.domain.model.HabitFrequency
import com.example.habitpal.domain.model.HabitTemplate
import com.example.habitpal.domain.repository.HabitRepository
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.launch
import javax.inject.Inject

@HiltViewModel
class OnboardingViewModel @Inject constructor(
    private val habitRepository: HabitRepository,
    private val userPreferences: UserPreferencesDataSource
) : ViewModel() {

    val templates: List<HabitTemplate> = HabitTemplate.defaults
    private val selectedTemplates = mutableSetOf<HabitTemplate>()

    fun toggleTemplate(template: HabitTemplate) {
        if (!selectedTemplates.add(template)) {
            selectedTemplates.remove(template)
        }
    }

    fun finishOnboarding(onComplete: () -> Unit) {
        viewModelScope.launch {
            selectedTemplates.forEach { template ->
                habitRepository.addHabit(
                    Habit(
                        title = template.title,
                        description = "",
                        frequency = HabitFrequency.DAILY
                    )
                )
            }
            userPreferences.setOnboardingComplete()
            onComplete()
        }
    }

    fun skipOnboarding(onComplete: () -> Unit) {
        viewModelScope.launch {
            userPreferences.setOnboardingComplete()
            onComplete()
        }
    }
}

